import React, { useState, useEffect } from 'react';
import { I18nData } from '../constants';
import { AlertCircle } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  onVerify: () => void;
  isVerifying: boolean;
  langData: I18nData;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, onVerify, isVerifying, langData }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [errors, setErrors] = useState<{ email?: string; password?: string }>({});
  const [touched, setTouched] = useState<{ email?: boolean; password?: boolean }>({});

  useEffect(() => {
    if (isOpen) {
      setEmail('');
      setPassword('');
      setErrors({});
      setTouched({});
      setRememberMe(false);
    }
  }, [isOpen]);

  const validateEmail = (email: string) => {
    if (!email) return langData.errors.emailRequired;
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) return langData.errors.emailInvalid;
    return undefined;
  };

  const validatePassword = (pwd: string) => {
    if (!pwd) return langData.errors.passwordRequired;
    return undefined;
  };

  const handleBlur = (field: 'email' | 'password') => {
    setTouched(prev => ({ ...prev, [field]: true }));
    if (field === 'email') {
      setErrors(prev => ({ ...prev, email: validateEmail(email) }));
    } else {
      setErrors(prev => ({ ...prev, password: validatePassword(password) }));
    }
  };

  const handleSubmit = () => {
    const emailError = validateEmail(email);
    const passwordError = validatePassword(password);

    setErrors({ email: emailError, password: passwordError });
    setTouched({ email: true, password: true });

    if (!emailError && !passwordError) {
      onVerify();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSubmit();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-white/60 backdrop-blur-sm animate-in fade-in duration-500" 
        onClick={onClose}
      />

      {/* Modal Content */}
      <div className="relative w-full max-w-[480px] bg-white rounded-[2.5rem] p-12 text-left shadow-[0_20px_60px_-15px_rgba(0,0,0,0.1)] animate-in zoom-in-95 duration-500 ease-out border border-slate-50">
        <h2 className="text-[2.5rem] font-bold text-[#1e293b] leading-tight mb-2 tracking-tight">
          {langData.welcomeBack}
        </h2>
        <p className="text-[#64748b] text-lg mb-10">
          {langData.subtitle}
        </p>

        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-[#334155] font-medium text-base ml-1 flex justify-between">
              {langData.emailLabel}
              {errors.email && touched.email && (
                <span className="text-red-500 text-xs font-bold flex items-center gap-1 animate-in fade-in slide-in-from-right-2">
                  <AlertCircle size={12} /> {errors.email}
                </span>
              )}
            </label>
            <input 
              type="email" 
              value={email}
              onChange={(e) => {
                setEmail(e.target.value);
                if (errors.email) setErrors(prev => ({ ...prev, email: undefined }));
              }}
              onBlur={() => handleBlur('email')}
              onKeyDown={handleKeyDown}
              placeholder="name@association.org"
              className={`w-full px-5 py-4 bg-[#f8fafc] border rounded-xl outline-none transition-all duration-300 text-base text-[#1e293b] placeholder:text-slate-400
                ${errors.email && touched.email 
                  ? 'border-red-500 bg-red-50/50 focus:border-red-500 focus:ring-4 focus:ring-red-500/5' 
                  : 'border-slate-100 focus:bg-white focus:border-[#4f46e5] focus:ring-4 focus:ring-[#4f46e5]/5'
                }`}
            />
          </div>

          <div className="space-y-2">
            <label className="text-[#334155] font-medium text-base ml-1 flex justify-between">
              {langData.passwordLabel}
              {errors.password && touched.password && (
                <span className="text-red-500 text-xs font-bold flex items-center gap-1 animate-in fade-in slide-in-from-right-2">
                  <AlertCircle size={12} /> {errors.password}
                </span>
              )}
            </label>
            <input 
              type="password" 
              value={password}
              onChange={(e) => {
                setPassword(e.target.value);
                if (errors.password) setErrors(prev => ({ ...prev, password: undefined }));
              }}
              onBlur={() => handleBlur('password')}
              onKeyDown={handleKeyDown}
              placeholder="••••••••"
              className={`w-full px-5 py-4 bg-[#f8fafc] border rounded-xl outline-none transition-all duration-300 text-base text-[#1e293b]
                ${errors.password && touched.password
                  ? 'border-red-500 bg-red-50/50 focus:border-red-500 focus:ring-4 focus:ring-red-500/5' 
                  : 'border-slate-100 focus:bg-white focus:border-[#4f46e5] focus:ring-4 focus:ring-[#4f46e5]/5'
                }`}
            />
          </div>
        </div>

        <div className="flex items-center justify-between mt-6 mb-8 px-1">
          <label className="flex items-center gap-2 cursor-pointer group">
            <input 
              type="checkbox" 
              checked={rememberMe}
              onChange={(e) => setRememberMe(e.target.checked)}
              className="w-4 h-4 rounded border-slate-300 text-[#4f46e5] focus:ring-[#4f46e5] cursor-pointer" 
            />
            <span className="text-sm text-[#64748b] group-hover:text-[#4f46e5] transition-colors">
              {langData.rememberMe}
            </span>
          </label>
          <button className="text-sm text-[#4f46e5] hover:text-[#4338ca] font-medium transition-colors">
            {langData.forgotPassword}
          </button>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isVerifying}
          className="w-full py-4 bg-[#4f46e5] hover:bg-[#4338ca] disabled:opacity-70 text-white font-bold text-lg rounded-2xl transition-all duration-300 shadow-[0_10px_20px_-5px_rgba(79,70,229,0.4)] hover:shadow-[0_15px_25px_-5px_rgba(79,70,229,0.5)] active:scale-[0.98]"
        >
          {isVerifying ? (
            <div className="flex items-center justify-center gap-2">
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            </div>
          ) : (
            langData.submit
          )}
        </button>

        <div className="text-center mt-6">
          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-slate-600 text-sm font-medium transition-colors uppercase tracking-widest"
          >
            返回
          </button>
        </div>
      </div>
    </div>
  );
};

export default Modal;

import React, { useRef, useEffect } from 'react';
import * as THREE from 'three';

interface Background3DProps {
  mouseX: number;
  mouseY: number;
}

class TechLine {
  mesh: THREE.Line;
  positions: Float32Array;
  velocity: THREE.Vector3;
  head: THREE.Vector3;
  segmentCount: number;
  speed: number;

  constructor(scene: THREE.Scene, bounds: { w: number; h: number; d: number }) {
    this.segmentCount = 80; // Length of the trail (线条拖尾长度)
    this.speed = 2.0 + Math.random() * 1.5; // Random speed (随机速度)

    const geometry = new THREE.BufferGeometry();
    this.positions = new Float32Array(this.segmentCount * 3);

    // Start from a random position within bounds
    this.head = new THREE.Vector3(
      (Math.random() - 0.5) * bounds.w,
      (Math.random() - 0.5) * bounds.h,
      (Math.random() - 0.5) * bounds.d
    );

    // Initialize all points at head position to avoid a streak from 0,0,0
    for (let i = 0; i < this.segmentCount; i++) {
      this.positions[i * 3] = this.head.x;
      this.positions[i * 3 + 1] = this.head.y;
      this.positions[i * 3 + 2] = this.head.z;
    }

    geometry.setAttribute('position', new THREE.BufferAttribute(this.positions, 3));

    // Tech colors: Indigo, Blue, Cyan (科技感配色)
    const colors = [0x4f46e5, 0x2563eb, 0x0891b2, 0x0ea5e9, 0x6366f1]; 
    const color = new THREE.Color(colors[Math.floor(Math.random() * colors.length)]);

    const material = new THREE.LineBasicMaterial({
      color: color,
      transparent: true,
      opacity: 0.5, // 半透明效果
      linewidth: 1, // Thin lines (细线条)
    });

    this.mesh = new THREE.Line(geometry, material);

    // Initial random velocity direction
    this.velocity = new THREE.Vector3(
      Math.random() - 0.5,
      Math.random() - 0.5,
      Math.random() - 0.5
    ).normalize().multiplyScalar(this.speed);

    scene.add(this.mesh);
  }

  update(bounds: { w: number; h: number; d: number }) {
    // 1. Move head (移动头部)
    this.head.add(this.velocity);

    // 2. Soft boundaries steering (碰到边界缓慢转向)
    const margin = 200;
    const turnFactor = 0.08;
    if (this.head.x > bounds.w / 2 - margin) this.velocity.x -= turnFactor;
    if (this.head.x < -bounds.w / 2 + margin) this.velocity.x += turnFactor;
    if (this.head.y > bounds.h / 2 - margin) this.velocity.y -= turnFactor;
    if (this.head.y < -bounds.h / 2 + margin) this.velocity.y += turnFactor;
    if (this.head.z > bounds.d / 2 - margin) this.velocity.z -= turnFactor;
    if (this.head.z < -bounds.d / 2 + margin) this.velocity.z += turnFactor;

    // 3. Random wandering - "Disorderly" movement (无序游走)
    // Add small random noise to velocity vector
    this.velocity.x += (Math.random() - 0.5) * 0.15;
    this.velocity.y += (Math.random() - 0.5) * 0.15;
    this.velocity.z += (Math.random() - 0.5) * 0.15;

    // Normalize to maintain constant speed
    this.velocity.normalize().multiplyScalar(this.speed);

    // 4. Update trail positions (Shift array)
    // Move every point to the position of the previous point
    for (let i = this.segmentCount - 1; i > 0; i--) {
      this.positions[i * 3] = this.positions[(i - 1) * 3];
      this.positions[i * 3 + 1] = this.positions[(i - 1) * 3 + 1];
      this.positions[i * 3 + 2] = this.positions[(i - 1) * 3 + 2];
    }

    // Set the first point to the new head position
    this.positions[0] = this.head.x;
    this.positions[1] = this.head.y;
    this.positions[2] = this.head.z;

    // Mark geometry for update
    this.mesh.geometry.attributes.position.needsUpdate = true;
  }
}

const Background3D: React.FC<Background3DProps> = ({ mouseX, mouseY }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    // Configuration
    const LINE_COUNT = 10; // 10 条线条
    const BOUNDS = { w: 2200, h: 1400, d: 800 }; // Movement space

    // Scene Setup
    const scene = new THREE.Scene();
    // No background color set here to allow CSS background (white) to show through via alpha: true

    const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 1, 5000);
    camera.position.z = 1000;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(window.innerWidth, window.innerHeight);
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // Create Tech Lines
    const techLines: TechLine[] = [];
    for (let i = 0; i < LINE_COUNT; i++) {
      techLines.push(new TechLine(scene, BOUNDS));
    }

    // Handle Resize
    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener('resize', handleResize);

    // Animation Loop
    let animationFrameId: number;
    const animate = () => {
      animationFrameId = requestAnimationFrame(animate);

      // Update lines logic
      techLines.forEach(line => line.update(BOUNDS));

      // Subtle Parallax Effect (Camera moves slightly with mouse)
      camera.position.x += (mouseX * 0.3 - camera.position.x) * 0.02;
      camera.position.y += (-mouseY * 0.3 - camera.position.y) * 0.02;
      camera.lookAt(0, 0, 0);

      renderer.render(scene, camera);
    };
    animate();

    return () => {
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(animationFrameId);
      if (rendererRef.current && containerRef.current) {
        containerRef.current.removeChild(rendererRef.current.domElement);
      }
      renderer.dispose();
      // Clean up geometries
      techLines.forEach(line => {
          line.mesh.geometry.dispose();
          (line.mesh.material as THREE.Material).dispose();
      });
    };
  }, [mouseX, mouseY]);

  return <div ref={containerRef} className="absolute inset-0 z-0 overflow-hidden pointer-events-none" />;
};

export default Background3D;

import React, { useState, useEffect } from 'react';
import { I18nData, Language, translations } from './constants';
import Background3D from './components/Background3D';
import LanguageSwitcher from './components/LanguageSwitcher';
import Modal from './components/Modal';
import Dashboard from './components/Dashboard';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(Language.ZH);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isVerifying, setIsVerifying] = useState(false);

  const t: I18nData = translations[lang];

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleLoginSubmit = () => {
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setIsModalOpen(false);
      setIsLoggedIn(true);
    }, 1200);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
  };

  if (isLoading) {
    return (
      <div className="fixed inset-0 bg-white z-[3000] flex flex-col items-center justify-center transition-all duration-1000 ease-in-out">
        <div className="relative w-20 h-20 mb-10">
