  return (
    <div className="relative w-screen h-screen overflow-hidden bg-white text-slate-900 select-none flex flex-col">
      <Background3D />

      {/* Header */}
      <header className="absolute top-0 left-0 right-0 p-8 flex justify-between items-center z-[100]">
