        </div>
        <LanguageSwitcher currentLang={lang} onLangChange={setLang} />
      </header>

      {/* Main Hero */}
      <main 
        className={`flex-1 flex flex-col items-center justify-center z-10 transition-all duration-1000 ease-in-out ${
          isModalOpen ? 'opacity-0 scale-95 blur-xl pointer-events-none' : 'opacity-100 scale-100 blur-0'
        }`}
      >
        <div className="text-center px-4 max-w-4xl">
          <p className="text-[#4f46e5] text-[11px] font-bold tracking-[0.5em] uppercase mb-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            Next Generation Intelligence
          </p>
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-black tracking-tight klein-blue-text mb-8 animate-in fade-in slide-in-from-bottom-8 duration-1000">
            HANGAICLOUD
          </h1>
          <p className="text-slate-400 text-lg md:text-xl font-medium max-w-2xl mx-auto mb-16 leading-relaxed animate-in fade-in slide-in-from-bottom-12 duration-1000 delay-200">
            构建连接智能与决策的数字桥梁。<br className="hidden md:block" /> 为现代行业协会提供深度 AI 洞察与自动化执行管理。
