          <NavItem icon={<Globe size={18} />} label={t.intelligence.title} active={activeTab === 'console'} onClick={() => setActiveTab('console')} />
          <NavItem icon={<Users size={18} />} label={t.partnerConnect.title} active={activeTab === 'partners'} onClick={() => setActiveTab('partners')} />
