            <h2 className="text-2xl font-semibold tracking-tight text-[#f5f5f7]">
              {activeTab === 'console' ? 'Intelligence' : 
               activeTab === 'library' ? 'Projects' :
               activeTab === 'partners' ? 'Partners' :
               activeTab === 'assets' ? 'Assets' : 'Settings'}
            </h2>
          </div>

          <div className="flex items-center gap-6">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#86868b] group-focus-within:text-white transition-colors" size={14} />
