              </div>
            </div>

            <div className="h-4 w-px bg-[#1d1d1f]" />

            <LanguageSwitcher currentLang={lang} onLangChange={setLang} />

            <button className="w-8 h-8 rounded-full bg-[#1d1d1f] flex items-center justify-center text-[#f5f5f7] hover:bg-[#2c2c2e] transition-colors">
              <span className="text-xs font-bold">AD</span>
            </button>
          </div>
        </header>

        {/* Content Container - Rounded corners if we wanted a "card" look, but full bleed is better for deep immersion */}
        <div className="flex-1 overflow-hidden relative">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

