const ProjectKanban: React.FC<{ language: Language }> = ({ language }) => {
  const [filter, setFilter] = useState<Category | 'All'>('All');
  const t = translations[language].projectKanban;

  // Map internal keys to translation keys
  const getFilterLabel = (key: string) => {
    switch (key) {
      case 'All': return t.filters.all;
      case 'Precision': return t.filters.precision;
      case 'Auto': return t.filters.auto;
      case 'Exclusive': return t.filters.exclusive;
      case 'Booth': return t.filters.booth;
      default: return key;
    }
  };

  const columns = [
    { status: 'Live', title: t.columns.active },
    { status: 'Upcoming', title: t.columns.pipeline },
    { status: 'Completed', title: t.columns.archive },
  ];

  const filteredProjects = useMemo(() => {
    return MOCK_PROJECTS.filter(p => filter === 'All' || p.category === filter);
  }, [filter]);

  return (
    <div className="h-full flex flex-col bg-black">
      {/* Filter Bar */}
      <div className="h-16 flex items-center px-10 border-b border-[#1d1d1f] shrink-0">
