               {col.status !== 'Completed' && (
                 <button className="w-full py-4 border border-dashed border-[#2c2c2e] rounded-[24px] text-[#86868b] text-sm font-medium hover:border-[#86868b] hover:text-white transition-all">
                   + {t.card.addProject}
