           <span className="w-1 h-1 bg-[#86868b] rounded-full" />
           <span>{project.date}</span>
        </p>
      </div>

      {project.status === 'Live' && (
        <div className="mb-4 p-3 bg-[#000000] rounded-xl border border-[#1d1d1f] flex gap-3 items-center">
            <img src={project.lastUpdate?.photo} className="w-10 h-10 rounded-lg object-cover opacity-80" />
            <div className="min-w-0">
               <div className="text-[10px] text-[#2997ff] font-bold uppercase mb-0.5">{t.card.latestUpdate}</div>
               <div className="text-[11px] text-[#f5f5f7] truncate">{project.lastUpdate?.action}</div>
            </div>
        </div>
      )}

      <div className="flex gap-2 mt-auto">
        {project.tags.map(tag => (
           <span key={tag} className="text-[10px] font-medium text-[#86868b] bg-[#1d1d1f] px-2 py-1 rounded-md">{tag}</span>
        ))}
      </div>
    </div>
  );
};

const ProjectKanban: React.FC<{ language: Language }> = ({ language }) => {
  const t = translations[language].projectKanban;

  // State for categories
  const [categories, setCategories] = useState<FilterCategory[]>([
    { key: 'Event', isCustom: false },
    { key: 'Conference', isCustom: false },
    { key: 'Exhibition', isCustom: false },
    { key: 'Party', isCustom: false },
    { key: 'Training', isCustom: false },
    { key: 'Promotion', isCustom: false },
  ]);

  const [filter, setFilter] = useState<Category | 'All'>('All');
  const [isEditing, setIsEditing] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  // Helper to get display label
  const getLabel = (cat: FilterCategory) => {
    if (cat.isCustom) return cat.key; // For custom tags, the key is the label
    // For default tags, look up translation
    const translationKey = cat.key.toLowerCase() as keyof typeof t.filters;
    return t.filters[translationKey] || cat.key;
  };

  const handleAddCategory = () => {
    if (newCategoryName.trim()) {
      setCategories([...categories, { key: newCategoryName.trim(), isCustom: true }]);
      setNewCategoryName('');
      setIsAdding(false);
    }
  };

  const handleDeleteCategory = (index: number) => {
    const newCats = [...categories];
    const removed = newCats.splice(index, 1)[0];
    setCategories(newCats);
    if (filter === removed.key) {
      setFilter('All');
    }
  };

  const columns = [
    { status: 'Live', title: t.columns.active },
    { status: 'Upcoming', title: t.columns.pipeline },
    { status: 'Completed', title: t.columns.archive },
  ];

  const filteredProjects = useMemo(() => {
    return MOCK_PROJECTS.filter(p => filter === 'All' || p.category === filter || (typeof filter === 'string' && p.category === filter));
  }, [filter]);

  return (
    <div className="h-full flex flex-col bg-black">
      {/* Filter Bar */}
      <div className="h-20 flex items-center px-6 md:px-10 border-b border-[#1d1d1f] shrink-0 gap-4">

        {/* Scrollable Filter List */}
        <div className="flex-1 overflow-x-auto no-scrollbar flex items-center gap-2 pr-4">
          <button 
            onClick={() => setFilter('All')}
            className={`shrink-0 px-5 py-2 rounded-full text-xs font-semibold transition-all ${
              filter === 'All'
              ? 'bg-[#f5f5f7] text-black shadow-lg shadow-white/10 scale-105' 
              : 'bg-[#161617] text-[#86868b] hover:text-white border border-[#2c2c2e]'
            }`}
          >
            {t.filters.all}
          </button>

          {categories.map((cat, idx) => (
            <div key={`${cat.key}-${idx}`} className="relative group shrink-0">
               <button 
                onClick={() => setFilter(cat.key)}
                className={`px-5 py-2 rounded-full text-xs font-semibold transition-all border ${
                  filter === cat.key
                  ? 'bg-[#2c2c2e] text-white border-[#2c2c2e] shadow-md' 
                  : 'bg-[#161617] text-[#86868b] border-[#2c2c2e] hover:text-white hover:border-[#86868b]'
                }`}
              >
                {getLabel(cat)}
              </button>

              {/* Delete Badge (Only in edit mode) */}
              {isEditing && (
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDeleteCategory(idx); }}
                  className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-red-500 rounded-full flex items-center justify-center text-white hover:scale-110 transition-transform shadow-sm z-10"
                >
                  <X size={10} strokeWidth={3} />
                </button>
              )}
            </div>
          ))}

          {/* Add Input Field */}
          {isAdding ? (
            <div className="flex items-center bg-[#1d1d1f] rounded-full px-2 border border-[#2997ff] shrink-0 animate-in fade-in zoom-in duration-200">
               <input 
                 autoFocus
                 type="text" 
                 value={newCategoryName}
                 onChange={(e) => setNewCategoryName(e.target.value)}
                 onKeyDown={(e) => e.key === 'Enter' && handleAddCategory()}
                 placeholder={t.filters.addPlaceholder}
                 className="bg-transparent border-none outline-none text-xs text-white px-2 py-2 w-28 placeholder:text-[#86868b]"
               />
               <button onClick={handleAddCategory} className="w-6 h-6 rounded-full bg-[#2997ff] flex items-center justify-center text-white hover:bg-[#007aff]">
                 <CheckCircle size={12} />
               </button>
               <button onClick={() => setIsAdding(false)} className="ml-1 w-6 h-6 flex items-center justify-center text-[#86868b] hover:text-white">
                 <X size={12} />
               </button>
            </div>
          ) : (
            <button 
              onClick={() => setIsAdding(true)}
              className="shrink-0 w-8 h-8 rounded-full border border-dashed border-[#86868b] flex items-center justify-center text-[#86868b] hover:text-white hover:border-white transition-colors"
              title="Add Category"
            >
              <Plus size={14} />
            </button>
          )}
        </div>

        {/* Action Tools */}
        <div className="flex items-center gap-2 pl-4 border-l border-[#1d1d1f]">
           <button 
             onClick={() => setIsEditing(!isEditing)}
             className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${
               isEditing ? 'bg-[#2997ff]/20 text-[#2997ff]' : 'text-[#86868b] hover:text-white'
             }`}
           >
             <Settings size={14} />
             <span className="hidden md:inline">{isEditing ? t.filters.done : t.filters.manage}</span>
           </button>
        </div>
      </div>

      {/* Board */}
      <div className="flex-1 overflow-x-auto p-10 flex gap-8">
        {columns.map(col => (
          <div key={col.title} className="w-[380px] shrink-0 flex flex-col">
            <h4 className="text-label mb-6 pl-2">{col.title} <span className="text-[#2c2c2e] ml-2">/</span> <span className="text-white ml-2">{filteredProjects.filter(p => p.status === col.status).length}</span></h4>
            <div className="flex-1 space-y-4">
               {filteredProjects.filter(p => p.status === col.status).map(p => (
                 <ProjectCard key={p.id} project={p} language={language} />
               ))}

               {col.status !== 'Completed' && (
                 <button className="w-full py-4 border border-dashed border-[#2c2c2e] rounded-[24px] text-[#86868b] text-sm font-medium hover:border-[#86868b] hover:text-white transition-all">
                   + {t.card.addProject}
                 </button>
               )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

