import React, { useState } from 'react';
import DigitalAssets from './DigitalAssets';
import PartnerConnect from './PartnerConnect';
import IntelligenceCenter from './IntelligenceCenter';
import ProjectKanban from './ProjectKanban';
import LanguageSwitcher from './LanguageSwitcher';
import { Language, translations } from '../constants';
import { 
  Globe, Users, Layout, Package, Settings, 
  Search, Bell, Command 
} from 'lucide-react';

interface DashboardProps {
  onLogout: () => void;
}

type TabType = 'console' | 'assets' | 'partners' | 'library' | 'config';

const Dashboard: React.FC<DashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<TabType>('console');
  const [lang, setLang] = useState<Language>(Language.ZH);

  const t = translations[lang];

  const renderContent = () => {
    switch (activeTab) {
      case 'assets':
        return <DigitalAssets language={lang} />;
      case 'partners':
        return <PartnerConnect language={lang} />;
      case 'library':
        return <ProjectKanban language={lang} />;
      case 'console':
      default:
        return <IntelligenceCenter language={lang} />;
    }
  };

  return (
    <div className="flex h-screen bg-black text-[#f5f5f7] overflow-hidden font-sans selection:bg-[#2997ff] selection:text-white">
      {/* Apple Style Sidebar */}
      <aside className="w-[260px] bg-black flex flex-col shrink-0 pt-10 pb-6 px-4 z-50">
        <div className="px-4 mb-10 flex items-center gap-3">
          <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center text-black font-bold text-lg">H</div>
          <span className="font-semibold text-lg tracking-tight">HANGAICLOUD</span>
        </div>

        <nav className="flex-1 space-y-1">
          <NavItem icon={<Globe size={18} />} label={t.intelligence.title} active={activeTab === 'console'} onClick={() => setActiveTab('console')} />
          <NavItem icon={<Users size={18} />} label={t.partnerConnect.title} active={activeTab === 'partners'} onClick={() => setActiveTab('partners')} />
          <NavItem icon={<Layout size={18} />} label={t.projectKanban.title} active={activeTab === 'library'} onClick={() => setActiveTab('library')} />
          <NavItem icon={<Package size={18} />} label={t.digitalAssets.title} active={activeTab === 'assets'} onClick={() => setActiveTab('assets')} />

          <div className="my-6 h-px bg-[#1d1d1f] mx-4" />

          <NavItem icon={<Settings size={18} />} label="系统配置" active={activeTab === 'config'} onClick={() => setActiveTab('config')} />
        </nav>

        <div className="mt-auto px-4">
          <button onClick={onLogout} className="text-sm text-[#86868b] hover:text-white transition-colors font-medium">
            Log out
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-black relative">
        {/* Floating Header */}
        <header className="h-20 flex items-center justify-between px-10 shrink-0 z-50">
          <div>
            <h2 className="text-2xl font-semibold tracking-tight text-[#f5f5f7]">
              {activeTab === 'console' ? 'Intelligence' : 
               activeTab === 'library' ? 'Projects' :
               activeTab === 'partners' ? 'Partners' :
               activeTab === 'assets' ? 'Assets' : 'Settings'}
            </h2>
          </div>

          <div className="flex items-center gap-6">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#86868b] group-focus-within:text-white transition-colors" size={14} />
              <input 
                type="text" 
                placeholder="Search" 
                className="bg-[#1d1d1f] hover:bg-[#2c2c2e] focus:bg-[#2c2c2e] rounded-lg py-2 pl-9 pr-4 text-sm w-48 transition-all outline-none text-white placeholder:text-[#86868b]" 
              />
              <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-1">
                 <Command size={10} className="text-[#86868b]" />
                 <span className="text-[10px] text-[#86868b] font-medium">K</span>
              </div>
            </div>

            <div className="h-4 w-px bg-[#1d1d1f]" />

            <LanguageSwitcher currentLang={lang} onLangChange={setLang} />

            <button className="w-8 h-8 rounded-full bg-[#1d1d1f] flex items-center justify-center text-[#f5f5f7] hover:bg-[#2c2c2e] transition-colors">
              <span className="text-xs font-bold">AD</span>
            </button>
          </div>
        </header>

        {/* Content Container - Rounded corners if we wanted a "card" look, but full bleed is better for deep immersion */}
        <div className="flex-1 overflow-hidden relative">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

