  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-lg transition-all text-[13px] font-medium group ${
    active ? 'bg-[#1c1c1e] text-white' : 'text-[#86868b] hover:text-white hover:bg-[#1c1c1e]/50'
  }`}>
    <span className={`${active ? 'text-[#2997ff]' : 'text-[#86868b] group-hover:text-white'} transition-colors`}>{icon}</span>
    <span className="tracking-wide truncate">{label}</span>
  </button>
);

